impl Solution { pub fn check_overlap(radius: i32, x_center: i32, y_center: i32, x1: i32, y1: i32, x2: i32, y2: i32) -> bool { let black_dx = if x_center < x1 { x1 - x_center } else if x_center > x2 { x_center - x2 } else { 0 }; let black_dy = if y_center < y1 { y1 - y_center } else if y_center > y2 { y_center - y2 } else { 0 }; black_dx * black_dx + black_dy * black_dy <= radius * radius } }